public String longestSubsequenceRepeatedK(String s, int k) {
    int[] counts = new int[26];
    for (char c : s.toCharArray())
        counts[c - 'a']++;
    StringBuilder seq = new StringBuilder();
    for (int i = 25; i >= 0; i--)
        for (int j = 0; j < counts[i] / k; j++)
            seq.append((char) ('a' + i));
    return seq.toString();
}
```

